package main

import (
	"io"
	"mime"
	"net/http"
	"os"
	"path/filepath"
	"strings"
)

const uploadsDir = "./uploads"

func fileHandler(w http.ResponseWriter, r *http.Request) {
	filename := r.URL.Query().Get("filename")
	if filename == "" {
		http.Error(w, "filename parameter is required", http.StatusBadRequest)
		return
	}

	absUploadsDir, err := filepath.Abs(uploadsDir)
	if err != nil {
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}

	requestedPath := filepath.Join(absUploadsDir, filename)
	
	cleanPath, err := filepath.Abs(requestedPath)
	if err != nil {
		http.Error(w, "Invalid file path", http.StatusBadRequest)
		return
	}

	realPath, err := filepath.EvalSymlinks(cleanPath)
	if err != nil {
		if os.IsNotExist(err) {
			http.Error(w, "File not found", http.StatusNotFound)
			return
		}
		realPath = cleanPath
	}

	if !strings.HasPrefix(realPath, absUploadsDir+string(filepath.Separator)) && realPath != absUploadsDir {
		http.Error(w, "Access denied", http.StatusForbidden)
		return
	}

	file, err := os.Open(realPath)
	if err != nil {
		if os.IsNotExist(err) {
			http.Error(w, "File not found", http.StatusNotFound)
		} else if os.IsPermission(err) {
			http.Error(w, "Access denied", http.StatusForbidden)
		} else {
			http.Error(w, "Internal server error", http.StatusInternalServerError)
		}
		return
	}
	defer file.Close()

	fileInfo, err := file.Stat()
	if err != nil {
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}

	if fileInfo.IsDir() {
		http.Error(w, "Cannot serve directories", http.StatusForbidden)
		return
	}

	ext := filepath.Ext(realPath)
	contentType := mime.TypeByExtension(ext)
	if contentType == "" {
		contentType = "application/octet-stream"
	}

	w.Header().Set("Content-Type", contentType)
	w.Header().Set("Content-Disposition", "inline; filename=\""+filepath.Base(realPath)+"\"")

	http.ServeContent(w, r, filepath.Base(realPath), fileInfo.ModTime(), file)
}

func main() {
	if err := os.MkdirAll(uploadsDir, 0755); err != nil {
		panic(err)
	}

	http.HandleFunc("/file", fileHandler)
	http.ListenAndServe(":8080", nil)
}